const files = $json.files || [];
if (!files.length) throw new Error('Nenhum arquivo encontrado');
return [{ json: files[0] }];

// =====================================================
// COMPARAÇÃO E SEPARAÇÃO INDIVIDUAL
// =====================================================

// 1. Pega os 79 itens da transformação
const planilhaItems = $('Transformar_Dados').all();

// 2. Pega os dados do banco (que vieram via input do Supabase)
const supabaseItems = $input.all();

// 3. Cria mapa do banco
const bancoMap = {};
for (const item of supabaseItems) {
  if (item.json && item.json.chapa) {
    bancoMap[String(item.json.chapa)] = item.json;
  }
}

// 4. Gera um item de output para CADA item da planilha
return planilhaItems.map(pItem => {
  const row = pItem.json;
  const chapa = String(row.chapa);
  const dadoBanco = bancoMap[chapa];

  if (!dadoBanco) {
    return { json: { ...row, operation: 'insert' } };
  }

  // Verificação de mudanças para evitar updates desnecessários
  let hasChanges = false;
  const ignore = ['id', 'created_at', 'updated_at'];
  for (const key of Object.keys(row)) {
    if (ignore.includes(key)) continue;
    if (String(row[key] || '') !== String(dadoBanco[key] || '')) {
      hasChanges = true;
      break;
    }
  }

  return { json: { ...row, operation: hasChanges ? 'update' : 'skip' } };
});

function excelSerialToDate(serial) {
  const excelEpoch = new Date(Date.UTC(1899, 11, 30));
  return new Date(excelEpoch.getTime() + Number(serial) * 86400000);
}

function parseDate(value) {
  if (!value) return null;
  if (value instanceof Date && !isNaN(value)) return value;
  if (typeof value === 'number') {
    const d = excelSerialToDate(value);
    return isNaN(d) ? null : d;
  }
  const str = String(value).trim();
  const match = str.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (match) {
    const [, d, m, y] = match;
    return new Date(Date.UTC(+y, +m - 1, +d));
  }
  const iso = new Date(str);
  return isNaN(iso) ? null : iso;
}

function formatISO(date) {
  if (!date) return null;
  return date.toISOString().split('T')[0];
}

function normalizeKey(key) {
  return key?.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-z0-9]/g, '') || '';
}

function getField(row, ...variants) {
  const keys = Object.keys(row);
  for (const v of variants) {
    const target = normalizeKey(v);
    for (const k of keys) {
      if (normalizeKey(k) === target) return row[k];
    }
  }
  return null;
}

const items = $input.all();
const output = [];

for (const item of items) {
  const row = item.json || {};

  const chapa = String(row['MAT'] || row['MATRICULA'] || row['CHAPA'] || row['chapa'] || '').trim();
  const nome = String(row['NOME'] || row['NOME COMPLETO'] || row['nome'] || '').trim();

  if (!chapa || !nome) continue;

  const rowData = {
    chapa,
    nome,
    funcao: getField(row, 'FUNCAO RM ATUALIZADA', 'FUNCAO', 'CARGO'),
    status: getField(row, 'STATUS', 'SITUACAO'),
    area: getField(row, 'AREA DE NEGOCIO', 'AREA'),
    cid: getField(row, 'CIP DE LIBERAÇÃO', 'CIP'),
    rh: getField(row, 'RH'),
    saude: getField(row, 'SAÚDE', 'SAUDE'),
    seguranca: getField(row, 'SEGURANÇA', 'SEGURANCA'),
    grd: getField(row, 'GRD'),
    obs_grd: getField(row, 'OBSERVAÇÃO GRD', 'OBS'),
    data_admissao: formatISO(parseDate(getField(row, 'DATA ADMISSÃO', 'ADMISSAO'))),
    liberacao_ecoordin: formatISO(parseDate(getField(row, 'DATA DE LIBERAÇÃO E-COORDINA'))),
    envio_cliente: formatISO(parseDate(getField(row, 'ENVIO PARA O CLIENTE', 'ENVIO CLIENTE')))
  };

  output.push({ json: rowData });
}

return output;
